// For each due follow-up, decide whether to send (parent quote still
// open/sent/viewed) or skip (parent already accepted/declined/expired).
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const dues = allOf('Fetch Due Follow-ups');
if (dues.length === 0) {
  return [{ json: { _no_work: true, ts: new Date().toISOString() } }];
}

const fmtMoney = function (cents) {
  const v = (parseInt(cents, 10) || 0) / 100;
  return '$' + v.toLocaleString('en-CA', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
};

const out = [];
for (const fu of dues) {
  const q = fu.quote_completed || null;
  if (!q) {
    out.push({ json: { _skip: true, followup_id: fu.id, reason: 'parent quote missing', patch_url: 'https://zqwatouqmqgkmaslydbr.supabase.co/rest/v1/quote_follow_ups?id=eq.' + fu.id, patch_body: { status: 'skipped', sent_at: new Date().toISOString() } } });
    continue;
  }
  // Skip if quote is already final (accepted/declined/expired)
  if (q.status === 'accepted' || q.status === 'declined' || q.status === 'expired') {
    out.push({ json: { _skip: true, followup_id: fu.id, reason: 'quote already ' + q.status, patch_url: 'https://zqwatouqmqgkmaslydbr.supabase.co/rest/v1/quote_follow_ups?id=eq.' + fu.id, patch_body: { status: 'skipped', sent_at: new Date().toISOString() } } });
    continue;
  }
  // Skip if expires_at has passed
  if (q.expires_at && new Date(q.expires_at).getTime() < Date.now()) {
    out.push({ json: { _skip: true, followup_id: fu.id, reason: 'quote expired', patch_url: 'https://zqwatouqmqgkmaslydbr.supabase.co/rest/v1/quote_follow_ups?id=eq.' + fu.id, patch_body: { status: 'skipped', sent_at: new Date().toISOString() } } });
    continue;
  }

  // Build the reminder email. Step-based copy varies in tone:
  //   step 1 (~3 days): gentle check-in
  //   step 2 (~7 days): value reinforcement
  //   step 3 (~14+ days): final nudge / book a call
  const tpl = q.quote_templates || {};
  const industryName = tpl.industry_name || q.industry_slug;
  let subject, intro, midline, cta;
  if (fu.step <= 1) {
    subject = 'Quick check-in on your Crystallux quote';
    intro   = 'Just a friendly nudge — wanted to make sure the quote I sent you didn\'t get buried.';
    midline = 'No pressure at all. Take your time. The quote is valid for 30 days.';
    cta     = 'Review the quote';
  } else if (fu.step === 2) {
    subject = 'Still thinking it over? Happy to answer questions.';
    intro   = 'Hope you\'re doing well. Realised I never asked — is there anything specific you wanted to dig into before deciding?';
    midline = 'Most folks have questions about implementation timeline or which add-ons actually matter for their specific setup. Happy to answer either over email or on a quick 15-min call.';
    cta     = 'Review the quote · or reply to schedule a call';
  } else {
    subject = 'Last note about your Crystallux quote';
    intro   = 'Promise this is the last nudge. The quote I sent expires soon — if it\'s a not-now, totally fair, and I won\'t keep emailing.';
    midline = 'If you do want to revisit later, just reply and I\'ll regenerate a fresh quote.';
    cta     = 'Review the quote';
  }

  const html =
    '<div style="font-family:Arial,Helvetica,sans-serif;font-size:15px;line-height:1.6;color:#333;max-width:640px">' +
    '<p>Hi ' + (q.full_name || 'there') + ',</p>' +
    '<p>' + intro + '</p>' +
    '<div style="background:#f8f7ff;border-left:4px solid #7C3AED;padding:18px 22px;margin:18px 0;border-radius:6px">' +
      '<div style="font-size:12px;color:#71717a;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px">Your quote</div>' +
      '<div style="font-size:22px;font-weight:700;color:#5B21B6">' + fmtMoney(q.total_monthly_cents) + ' <span style="font-size:13px;color:#71717a;font-weight:400">/mo</span></div>' +
      '<div style="font-size:12px;color:#52525b;margin-top:4px">' + (q.base_tier || 'starter') + ' tier · ' + industryName + ' · first-year ' + fmtMoney(q.total_first_year_cents) + '</div>' +
    '</div>' +
    '<p>' + midline + '</p>' +
    '<p style="margin-top:24px"><a href="https://crystallux.org/quote/' + q.id + '" style="display:inline-block;padding:10px 20px;background:#7C3AED;color:#fff;text-decoration:none;border-radius:6px;font-weight:600">' + cta + '</a></p>' +
    '<p>Talk soon,<br><strong>Mary Akintunde · Crystallux</strong></p>' +
    '</div>';

  out.push({ json: {
    followup_id:        fu.id,
    quote_id:           q.id,
    step:               fu.step,
    postmark_body: {
      From:    'info@crystallux.org',
      To:      q.email,
      Subject: subject,
      HtmlBody: html,
      MessageStream: 'outbound',
      Tag: 'quote-followup',
      Metadata: { quote_id: q.id, followup_id: fu.id, step: String(fu.step) }
    }
  } });
}
return out;

const postmark = $input.item.json;
const d = $('Build Reminders').itemMatching($itemIndex).json;
const sentOk = !!(postmark && postmark.MessageID);
const body = sentOk
  ? { status: 'sent', sent_at: new Date().toISOString(), postmark_message_id: postmark.MessageID }
  : { status: 'pending', sent_at: null, postmark_message_id: null };
// If postmark errored, leave status=pending so next tick retries
// (unless ErrorCode indicates a hard failure like 406 inactive recipient).
if (!sentOk && postmark && postmark.ErrorCode === 406) {
  body.status = 'skipped';
  body.sent_at = new Date().toISOString();
}
return { json: {
  patch_url: 'https://zqwatouqmqgkmaslydbr.supabase.co/rest/v1/quote_follow_ups?id=eq.' + d.followup_id,
  patch_body: body,
  postmark_status: sentOk ? 'sent' : 'failed',
  postmark_error_code: postmark && postmark.ErrorCode ? postmark.ErrorCode : null,
  postmark_message: postmark && postmark.Message ? postmark.Message : null
} };
